INSERT INTO public.bill_templates (issue_key, display_name, description, stances) VALUES ('abortion', 'Abortion Rights', 'Federal standards for reproductive health access and provider regulation.', '[{"stance_key":"ban","label":"National Ban","summary":"Prohibit abortion nationwide with limited medical exceptions.","policy_value":-2,"full_text":"A BILL To establish a nationwide prohibition on elective abortion.\n\nBe it enacted by the Senate and House of Representatives of the United States of America in Congress assembled,\n\nSECTION 1. DEFINITIONS.—The term ''abortion'' means the use or prescription of any instrument, medicine, drug, or other substance or device intentionally to terminate a clinically diagnosable pregnancy except where necessary to prevent the death of the pregnant patient or to avert serious risk of substantial and irreversible physical impairment of a major bodily function.\n\nSECTION 2. PROHIBITION.—It shall be unlawful for any person to perform or attempt to perform an abortion, or knowingly to assist in performing an abortion, in the United States or affecting interstate commerce.\n\nSECTION 3. ENFORCEMENT.—The Attorney General may bring a civil action for appropriate relief. Nothing herein shall be construed to authorize prosecution of the pregnant patient.\n\nSEC. 99. SEVERABILITY.\nIf any provision of this Act, or the application thereof to any person or circumstance, is held invalid, the remainder of the Act, and the application of such provisions to other persons or circumstances, shall not be affected thereby.\n\nSEC. 100. EFFECTIVE DATE.\nThis Act shall take effect on the date of the enactment of this Act."},{"stance_key":"restrict","label":"Restrict After First Trimester","summary":"Allow early access with strict limits after viability and hospital-only requirements.","policy_value":-1,"full_text":"A BILL To regulate abortion services after the first trimester while preserving early access.\n\nBe it enacted by the Senate and House of Representatives of the United States of America in Congress assembled,\n\nSECTION 1. PERMITTED SERVICES.—During the first fourteen weeks of pregnancy, a licensed physician may provide abortion services consistent with applicable state licensing and informed-consent requirements.\n\nSECTION 2. POST-FOURTEEN WEEKS.—After fourteen weeks'' gestation, abortion may be performed only in a hospital licensed by the State, and only where two physicians certify that continuation of the pregnancy poses a serious risk to the life or health of the pregnant patient.\n\nSECTION 3. REPORTING.—States shall maintain de-identified statistical reports submitted annually to the Secretary of Health and Human Services.\n\nSEC. 99. SEVERABILITY.\nIf any provision of this Act, or the application thereof to any person or circumstance, is held invalid, the remainder of the Act, and the application of such provisions to other persons or circumstances, shall not be affected thereby.\n\nSEC. 100. EFFECTIVE DATE.\nThis Act shall take effect on the date of the enactment of this Act."},{"stance_key":"codify_roe","label":"Codify Roe Framework","summary":"Statutorily restore pre-Dobbs undue-burden and viability standards.","policy_value":1,"full_text":"A BILL To codify the essential holdings of Roe v. Wade and Planned Parenthood of Southeastern Pa. v. Casey.\n\nBe it enacted by the Senate and House of Representatives of the United States of America in Congress assembled,\n\nSECTION 1. FUNDAMENTAL RIGHT.—Prior to fetal viability, the choice to terminate a pregnancy shall not be unduly burdened by federal or state regulation.\n\nSECTION 2. VIABILITY STANDARD.—After viability, Congress recognizes the concurrent interests in potential life and maternal health; regulations shall be permitted only where they further a compelling state interest and employ the least restrictive means.\n\nSECTION 3. PREEMPTION CLAUSE.—Any state law that imposes an undue burden on abortion access prior to viability is preempted to the extent of the inconsistency.\n\nSEC. 99. SEVERABILITY.\nIf any provision of this Act, or the application thereof to any person or circumstance, is held invalid, the remainder of the Act, and the application of such provisions to other persons or circumstances, shall not be affected thereby.\n\nSEC. 100. EFFECTIVE DATE.\nThis Act shall take effect on the date of the enactment of this Act."},{"stance_key":"constitutional_right","label":"Constitutional Right","summary":"Declare reproductive autonomy a federal statutory constitutional entitlement nationwide.","policy_value":2,"full_text":"A BILL To recognize and enforce a federal statutory right to reproductive autonomy.\n\nBe it enacted by the Senate and House of Representatives of the United States of America in Congress assembled,\n\nSECTION 1. RIGHT DECLARED.—Every person possesses the right to make and effectuate decisions about pregnancy, including the right to obtain abortion services without medically unnecessary delay or requirement.\n\nSECTION 2. PROVIDER PROTECTION.—No officer or employee of the United States or any State shall penalize, sanction, or discriminate against a health care provider for furnishing lawful abortion services.\n\nSECTION 3. PRIVATE RIGHT OF ACTION.—Any person aggrieved by a violation of this Act may bring an action in a United States district court for declaratory and injunctive relief and for damages as the court deems appropriate.\n\nSEC. 99. SEVERABILITY.\nIf any provision of this Act, or the application thereof to any person or circumstance, is held invalid, the remainder of the Act, and the application of such provisions to other persons or circumstances, shall not be affected thereby.\n\nSEC. 100. EFFECTIVE DATE.\nThis Act shall take effect on the date of the enactment of this Act."}]'::jsonb) ON CONFLICT (issue_key) DO UPDATE SET display_name = excluded.display_name, description = excluded.description, stances = excluded.stances;
INSERT INTO public.bill_templates (issue_key, display_name, description, stances) VALUES ('gun_control', 'Gun Control', 'Federal firearms commerce, background checks, and assault-style weapons policy.', '[{"stance_key":"deregulate","label":"Deregulate Interstate Carry","summary":"National reciprocity for concealed carry and limits on ATF rulemaking.","policy_value":-2,"full_text":"A BILL To protect lawful interstate transportation and recognition of concealed-carry privileges.\n\nBe it enacted by the Senate and House of Representatives of the United States of America in Congress assembled,\n\nSECTION 1. RECIPROCITY.—Any person who is not prohibited from possessing firearms under Federal law and who holds a valid concealed-carry permit issued by any State may carry a concealed handgun in any other State that issues concealed-carry permits.\n\nSECTION 2. TRANSPORTATION.—Firearms unloaded and locked in a vehicle trunk or locked container shall not be deemed ''carrying'' for purposes of local prohibitions during continuous interstate travel.\n\nSECTION 3. RULEMAKING MORATORIUM.—For ten years following enactment, the Bureau of Alcohol, Tobacco, Firearms and Explosives shall not promulgate rules that reclassify commonly possessed semi-automatic rifles as Title II weapons absent express congressional authorization.\n\nSEC. 99. SEVERABILITY.\nIf any provision of this Act, or the application thereof to any person or circumstance, is held invalid, the remainder of the Act, and the application of such provisions to other persons or circumstances, shall not be affected thereby.\n\nSEC. 100. EFFECTIVE DATE.\nThis Act shall take effect on the date of the enactment of this Act."},{"stance_key":"background_checks","label":"Universal Background Checks","summary":"Close private-sale loopholes with NICS checks and misdemeanor domestic-violence alignment.","policy_value":-1,"full_text":"A BILL To require background checks for all firearm transfers.\n\nBe it enacted by the Senate and House of Representatives of the United States of America in Congress assembled,\n\nSECTION 1. LICENSED DEALER TRANSFERS.—All transfers involving a licensed dealer shall be processed through the National Instant Criminal Background Check System prior to delivery.\n\nSECTION 2. PRIVATE TRANSFERS.—Private parties shall complete transfers only through a licensed dealer or designated law-enforcement agency, except for temporary loans at shooting ranges and transfers between immediate family members residing in the same household.\n\nSECTION 3. RETENTION.—Dealers shall retain Form 4473 records for twenty years and make them available to ATF for tracing upon lawful request.\n\nSEC. 99. SEVERABILITY.\nIf any provision of this Act, or the application thereof to any person or circumstance, is held invalid, the remainder of the Act, and the application of such provisions to other persons or circumstances, shall not be affected thereby.\n\nSEC. 100. EFFECTIVE DATE.\nThis Act shall take effect on the date of the enactment of this Act."},{"stance_key":"assault_weapons_ban","label":"Assault Weapons Ban","summary":"Prohibit new sales of listed semi-automatic rifles and large-capacity magazines.","policy_value":1,"full_text":"A BILL To regulate assault weapons and large capacity ammunition feeding devices.\n\nBe it enacted by the Senate and House of Representatives of the United States of America in Congress assembled,\n\nSECTION 1. DEFINITION.—The term ''assault weapon'' means a semi-automatic rifle that accepts a detachable magazine and has any two listed military-style features set forth in subsection (b) of this section.\n\nSECTION 2. PROHIBITED CONDUCT.—It shall be unlawful to manufacture, import, sell, or transfer an assault weapon or a large capacity ammunition feeding device holding more than ten rounds, except to the United States or a law enforcement agency.\n\nSECTION 3. GRANDFATHERING.—Persons lawfully possessing covered weapons before the effective date may retain them if registered pursuant to regulations issued by the Attorney General.\n\nSEC. 99. SEVERABILITY.\nIf any provision of this Act, or the application thereof to any person or circumstance, is held invalid, the remainder of the Act, and the application of such provisions to other persons or circumstances, shall not be affected thereby.\n\nSEC. 100. EFFECTIVE DATE.\nThis Act shall take effect on the date of the enactment of this Act."},{"stance_key":"full_ban","label":"Mandatory Buyback","summary":"Phase out civilian possession of semi-automatic centerfire rifles and fund buybacks.","policy_value":2,"full_text":"A BILL To reduce civilian possession of military-style firearms through a compensated transition program.\n\nBe it enacted by the Senate and House of Representatives of the United States of America in Congress assembled,\n\nSECTION 1. COVERED FIREARMS.—The term ''covered firearm'' includes semi-automatic centerfire rifles capable of accepting detachable magazines and semi-automatic pistols with certain listed features.\n\nSECTION 2. BUYBACK PROGRAM.—The Attorney General shall establish a voluntary buyback program compensating lawful owners at fair market value, funded through appropriations authorized in this Act.\n\nSECTION 3. POSSESSION AFTER WINDOW.—After the sunset of the buyback period, civilian possession of covered firearms outside narrow sporting exemptions shall be unlawful except for licensed museums.\n\nSEC. 99. SEVERABILITY.\nIf any provision of this Act, or the application thereof to any person or circumstance, is held invalid, the remainder of the Act, and the application of such provisions to other persons or circumstances, shall not be affected thereby.\n\nSEC. 100. EFFECTIVE DATE.\nThis Act shall take effect on the date of the enactment of this Act."}]'::jsonb) ON CONFLICT (issue_key) DO UPDATE SET display_name = excluded.display_name, description = excluded.description, stances = excluded.stances;
INSERT INTO public.bill_templates (issue_key, display_name, description, stances) VALUES ('healthcare', 'Healthcare System', 'Coverage models, subsidies, and public plan options.', '[{"stance_key":"privatize","label":"Block Grants & HSAs","summary":"Convert Medicaid expansion funds to state block grants and expand HSAs.","policy_value":-2,"full_text":"A BILL To convert certain Medicaid funds into flexible state block grants and expand health savings accounts.\n\nBe it enacted by the Senate and House of Representatives of the United States of America in Congress assembled,\n\nSECTION 1. BLOCK GRANTS.—Federal Medicaid matching payments for the adult expansion population shall be replaced by capped allotments to States beginning in fiscal year following enactment.\n\nSECTION 2. HSA EXPANSION.—Annual contribution limits shall be doubled and qualified medical expenses shall include direct primary care membership fees.\n\nSECTION 3. STATE WAIVER DEFAULT.—States shall have a rebuttable presumption of approval for waivers that introduce work requirements for able-bodied adults without dependents.\n\nSEC. 99. SEVERABILITY.\nIf any provision of this Act, or the application thereof to any person or circumstance, is held invalid, the remainder of the Act, and the application of such provisions to other persons or circumstances, shall not be affected thereby.\n\nSEC. 100. EFFECTIVE DATE.\nThis Act shall take effect on the date of the enactment of this Act."},{"stance_key":"aca_repeal","label":"Repeal ACA Individual Mandate Provisions","summary":"Remove individual mandate tax and associated reporting while preserving pre-existing condition rules.","policy_value":-1,"full_text":"A BILL To amend the Internal Revenue Code of 1986 to repeal certain Affordable Care Act tax provisions.\n\nBe it enacted by the Senate and House of Representatives of the United States of America in Congress assembled,\n\nSECTION 1. INDIVIDUAL SHARED RESPONSIBILITY.—Section 5000A of the Internal Revenue Code of 1986 is repealed effective for taxable years beginning after December 31 of the year of enactment.\n\nSECTION 2. REPORTING.—Employers shall not be required to report coverage offers solely for purposes of the repealed penalty.\n\nSECTION 3. INSURANCE REFORMS.—Sections 2711 through 2719 of the Public Health Service Act shall remain in force, including protections for dependents and prohibitions on lifetime limits for essential health benefits.\n\nSEC. 99. SEVERABILITY.\nIf any provision of this Act, or the application thereof to any person or circumstance, is held invalid, the remainder of the Act, and the application of such provisions to other persons or circumstances, shall not be affected thereby.\n\nSEC. 100. EFFECTIVE DATE.\nThis Act shall take effect on the date of the enactment of this Act."},{"stance_key":"public_option","label":"Public Option","summary":"Medicare-like plan offered on all Marketplaces with negotiated rates.","policy_value":1,"full_text":"A BILL To establish a public health insurance option on Federal and State Marketplaces.\n\nBe it enacted by the Senate and House of Representatives of the United States of America in Congress assembled,\n\nSECTION 1. ESTABLISHMENT.—The Secretary of Health and Human Services shall offer a ''Federal Health Plan'' in every rating area where a qualified health plan is offered.\n\nSECTION 2. PAYMENT RATES.—The Federal Health Plan shall reimburse providers at not less than Medicare rates and not more than Medicare rates plus fifteen percent.\n\nSECTION 3. SUBSIDIES.—Advance premium tax credits and cost-sharing reductions shall apply to Federal Health Plan enrollees on the same basis as for qualified health plans.\n\nSEC. 99. SEVERABILITY.\nIf any provision of this Act, or the application thereof to any person or circumstance, is held invalid, the remainder of the Act, and the application of such provisions to other persons or circumstances, shall not be affected thereby.\n\nSEC. 100. EFFECTIVE DATE.\nThis Act shall take effect on the date of the enactment of this Act."},{"stance_key":"universal","label":"Medicare for All Framework","summary":"Single-payer national health insurance with phased provider transition.","policy_value":2,"full_text":"A BILL To establish a single-payer national health program.\n\nBe it enacted by the Senate and House of Representatives of the United States of America in Congress assembled,\n\nSECTION 1. PROGRAM CREATION.—There is hereby established the United States National Health Insurance Program to finance medically necessary services without cost-sharing at the point of service for covered individuals.\n\nSECTION 2. COVERED BENEFITS.—Benefits shall include hospital, physician, mental health, dental, vision, prescription drug, and long-term supports and services as defined by the Board.\n\nSECTION 3. TRANSITION.—Private Medicare Advantage contracts shall sunset pursuant to a schedule issued by the Secretary, with continuity protections for enrollees.\n\nSEC. 99. SEVERABILITY.\nIf any provision of this Act, or the application thereof to any person or circumstance, is held invalid, the remainder of the Act, and the application of such provisions to other persons or circumstances, shall not be affected thereby.\n\nSEC. 100. EFFECTIVE DATE.\nThis Act shall take effect on the date of the enactment of this Act."}]'::jsonb) ON CONFLICT (issue_key) DO UPDATE SET display_name = excluded.display_name, description = excluded.description, stances = excluded.stances;
INSERT INTO public.bill_templates (issue_key, display_name, description, stances) VALUES ('immigration', 'Immigration Policy', 'Border security, enforcement, and pathways to status.', '[{"stance_key":"closed_borders","label":"Closed Borders","summary":"Moratorium on most new immigrant visas pending review.","policy_value":-2,"full_text":"A BILL To pause certain immigrant admissions for national security review.\n\nBe it enacted by the Senate and House of Representatives of the United States of America in Congress assembled,\n\nSECTION 1. MORATORIUM.—For a period of thirty-six months, the annual numerical limitation under section 201 of the Immigration and Nationality Act shall be reduced by fifty percent for family-sponsored and employment-based preferences, except for spouses and minor children of United States citizens.\n\nSECTION 2. ASYLUM.—All applicants for asylum shall be detained or subject to supervised release with electronic monitoring pending credible-fear adjudication.\n\nSECTION 3. SANCTUARY PREEMPTION.—No State or political subdivision may restrict communication with the Department of Homeland Security regarding citizenship or immigration status.\n\nSEC. 99. SEVERABILITY.\nIf any provision of this Act, or the application thereof to any person or circumstance, is held invalid, the remainder of the Act, and the application of such provisions to other persons or circumstances, shall not be affected thereby.\n\nSEC. 100. EFFECTIVE DATE.\nThis Act shall take effect on the date of the enactment of this Act."},{"stance_key":"enforcement_first","label":"Enforcement First","summary":"Mandatory E-Verify, border technology surge, and merit-based caps.","policy_value":-1,"full_text":"A BILL To strengthen employment eligibility verification and border security.\n\nBe it enacted by the Senate and House of Representatives of the United States of America in Congress assembled,\n\nSECTION 1. E-VERIFY.—All employers shall participate in E-Verify for new hires within two years of enactment.\n\nSECTION 2. BORDER INFRASTRUCTURE.—There are authorized to be appropriated such sums as may be necessary for pedestrian fencing, sensors, and ports-of-entry modernization.\n\nSECTION 3. VISA CAPS.—The Secretary of State shall allocate employment-based visas using a points system prioritizing education, language proficiency, and labor-market needs.\n\nSEC. 99. SEVERABILITY.\nIf any provision of this Act, or the application thereof to any person or circumstance, is held invalid, the remainder of the Act, and the application of such provisions to other persons or circumstances, shall not be affected thereby.\n\nSEC. 100. EFFECTIVE DATE.\nThis Act shall take effect on the date of the enactment of this Act."},{"stance_key":"pathway_to_citizenship","label":"Pathway to Citizenship","summary":"Earned legalization for long-term residents with security triggers.","policy_value":1,"full_text":"A BILL To provide an earned pathway to lawful permanent resident status.\n\nBe it enacted by the Senate and House of Representatives of the United States of America in Congress assembled,\n\nSECTION 1. ELIGIBILITY.—A noncitizen who has been continuously physically present in the United States since January 1, 2015, and who satisfies background and tax requirements may apply for conditional resident status.\n\nSECTION 2. CONDITIONAL PERIOD.—Conditional status shall be granted for eight years, after which the Secretary may remove conditions upon demonstration of employment, education, or military service benchmarks.\n\nSECTION 3. BORDER TRIGGERS.—Implementation of final green-card applications for certain categories shall be tied to certification of biometric entry-exit completion at major air and sea ports.\n\nSEC. 99. SEVERABILITY.\nIf any provision of this Act, or the application thereof to any person or circumstance, is held invalid, the remainder of the Act, and the application of such provisions to other persons or circumstances, shall not be affected thereby.\n\nSEC. 100. EFFECTIVE DATE.\nThis Act shall take effect on the date of the enactment of this Act."},{"stance_key":"open_borders","label":"Open Borders","summary":"Demilitarize interior enforcement and expand humanitarian parole.","policy_value":2,"full_text":"A BILL To refocus immigration enforcement on serious criminal conduct and expand lawful entry channels.\n\nBe it enacted by the Senate and House of Representatives of the United States of America in Congress assembled,\n\nSECTION 1. INTERIOR ENFORCEMENT.—The Department of Homeland Security shall not conduct civil immigration arrests at schools, hospitals, or places of worship absent exigent circumstances involving violent felonies.\n\nSECTION 2. PAROLE.—The Secretary shall establish categorical parole programs for climate-displaced persons and family reunification cases subject to fraud-prevention screening.\n\nSECTION 3. VISA AVAILABILITY.—Unused employment-based visa numbers shall roll over to family-based categories in the following fiscal year.\n\nSEC. 99. SEVERABILITY.\nIf any provision of this Act, or the application thereof to any person or circumstance, is held invalid, the remainder of the Act, and the application of such provisions to other persons or circumstances, shall not be affected thereby.\n\nSEC. 100. EFFECTIVE DATE.\nThis Act shall take effect on the date of the enactment of this Act."}]'::jsonb) ON CONFLICT (issue_key) DO UPDATE SET display_name = excluded.display_name, description = excluded.description, stances = excluded.stances;
INSERT INTO public.bill_templates (issue_key, display_name, description, stances) VALUES ('minimum_wage', 'Minimum Wage', 'Federal minimum wage levels and indexing.', '[{"stance_key":"freeze","label":"Freeze Federal Floor","summary":"Maintain current federal minimum wage and preempt state increases above a cap.","policy_value":-2,"full_text":"A BILL To freeze the federal minimum wage and harmonize state preemption standards.\n\nBe it enacted by the Senate and House of Representatives of the United States of America in Congress assembled,\n\nSECTION 1. RATE.—The minimum wage under section 6(a)(1) of the Fair Labor Standards Act of 1938 shall remain at the rate in effect on the day before the date of enactment of this Act for ten years.\n\nSECTION 2. PREEMPTION.—No State or locality may require an hourly wage more than twenty percent above the federal minimum for employers engaged in interstate commerce below five hundred employees.\n\nSECTION 3. TIP CREDIT.—The cash wage required for tipped employees shall not increase for ten years.\n\nSEC. 99. SEVERABILITY.\nIf any provision of this Act, or the application thereof to any person or circumstance, is held invalid, the remainder of the Act, and the application of such provisions to other persons or circumstances, shall not be affected thereby.\n\nSEC. 100. EFFECTIVE DATE.\nThis Act shall take effect on the date of the enactment of this Act."},{"stance_key":"raise_to_15","label":"Raise to $15","summary":"Phased increase to $15/hour by 2028 with youth subminimum sunset.","policy_value":-1,"full_text":"A BILL To increase the federal minimum wage to $15 an hour.\n\nBe it enacted by the Senate and House of Representatives of the United States of America in Congress assembled,\n\nSECTION 1. SCHEDULE.—Section 6(a)(1) of the Fair Labor Standards Act of 1938 is amended to provide annual stepped increases until the hourly rate equals $15.00.\n\nSECTION 2. YOUTH SUBMINIMUM.—The Secretary shall phase out separate youth subminimum wages for newly covered employees over five years.\n\nSECTION 3. SMALL BUSINESS CREDIT.—Employers with fewer than twenty employees may claim a payroll tax credit equal to a percentage of increased wage costs as prescribed by the Secretary of the Treasury.\n\nSEC. 99. SEVERABILITY.\nIf any provision of this Act, or the application thereof to any person or circumstance, is held invalid, the remainder of the Act, and the application of such provisions to other persons or circumstances, shall not be affected thereby.\n\nSEC. 100. EFFECTIVE DATE.\nThis Act shall take effect on the date of the enactment of this Act."},{"stance_key":"raise_to_20","label":"Raise to $20","summary":"Accelerated path to $20 with regional COLA adjustments.","policy_value":1,"full_text":"A BILL To establish a $20 federal minimum wage with regional adjustments.\n\nBe it enacted by the Senate and House of Representatives of the United States of America in Congress assembled,\n\nSECTION 1. BASE RATE.—The minimum wage shall reach $20.00 per hour not later than five years after enactment.\n\nSECTION 2. REGIONAL ADJUSTMENTS.—The Bureau of Labor Statistics shall publish regional price parities; employers in low-cost areas may apply a discount not to exceed seven percent of the base rate.\n\nSECTION 3. INDEXING.—Beginning in the sixth year, the minimum wage shall increase annually by the percentage increase in the Consumer Price Index for Urban Wage Earners and Clerical Workers.\n\nSEC. 99. SEVERABILITY.\nIf any provision of this Act, or the application thereof to any person or circumstance, is held invalid, the remainder of the Act, and the application of such provisions to other persons or circumstances, shall not be affected thereby.\n\nSEC. 100. EFFECTIVE DATE.\nThis Act shall take effect on the date of the enactment of this Act."},{"stance_key":"living_wage_indexed","label":"Living Wage + Indexing","summary":"Tie minimum to county median rent and index automatically.","policy_value":2,"full_text":"A BILL To establish a living wage tied to housing costs.\n\nBe it enacted by the Senate and House of Representatives of the United States of America in Congress assembled,\n\nSECTION 1. LIVING WAGE FORMULA.—The Secretary of Labor shall annually publish a county-level living wage equal to forty percent of median gross rent for a two-bedroom unit divided by one hundred thirty hours.\n\nSECTION 2. FLOOR AND CEILING.—No county rate shall be below $18.00 or above $35.00 in the first five years, after which the ceiling shall float with national median wages.\n\nSECTION 3. ENFORCEMENT.—The Secretary may assess civil penalties for willful violations and shall coordinate data sharing with the Department of Housing and Urban Development.\n\nSEC. 99. SEVERABILITY.\nIf any provision of this Act, or the application thereof to any person or circumstance, is held invalid, the remainder of the Act, and the application of such provisions to other persons or circumstances, shall not be affected thereby.\n\nSEC. 100. EFFECTIVE DATE.\nThis Act shall take effect on the date of the enactment of this Act."}]'::jsonb) ON CONFLICT (issue_key) DO UPDATE SET display_name = excluded.display_name, description = excluded.description, stances = excluded.stances;
INSERT INTO public.bill_templates (issue_key, display_name, description, stances) VALUES ('climate', 'Climate Policy', 'Federal energy mix, emissions targets, and investment programs.', '[{"stance_key":"deregulate","label":"Deregulate Energy","summary":"Limit EPA GHG rules under major questions doctrine analogue.","policy_value":-2,"full_text":"A BILL To limit agency authority to regulate greenhouse gas emissions from stationary sources absent express statutory standards.\n\nBe it enacted by the Senate and House of Representatives of the United States of America in Congress assembled,\n\nSECTION 1. STATUTORY BAR.—No agency may promulgate economy-wide performance standards for greenhouse gas emissions from existing power plants unless Congress enacts a joint resolution approving the specific numeric limit.\n\nSECTION 2. PERMITTING.—National Environmental Policy Act reviews for fossil fuel pipelines shall presumptively conclude within one year absent a showing of significant new information.\n\nSECTION 3. EXPORTS.—Liquefied natural gas export terminals shall receive deemed approval if the Department of Energy fails to act within ninety days.\n\nSEC. 99. SEVERABILITY.\nIf any provision of this Act, or the application thereof to any person or circumstance, is held invalid, the remainder of the Act, and the application of such provisions to other persons or circumstances, shall not be affected thereby.\n\nSEC. 100. EFFECTIVE DATE.\nThis Act shall take effect on the date of the enactment of this Act."},{"stance_key":"voluntary_targets","label":"Voluntary Industry Targets","summary":"Tax credits for voluntary reductions without binding caps.","policy_value":-1,"full_text":"A BILL To incentivize voluntary greenhouse gas intensity reductions.\n\nBe it enacted by the Senate and House of Representatives of the United States of America in Congress assembled,\n\nSECTION 1. CREDIT.—Manufacturers that achieve a ten percent reduction in facility-level greenhouse gas intensity compared to a baseline year may claim a refundable tax credit as prescribed by the Secretary of the Treasury.\n\nSECTION 2. REPORTING.—Participation shall be voluntary; trade secrets submitted to the Environmental Protection Agency shall be protected from disclosure except in aggregate form.\n\nSECTION 3. RESEARCH.—There are authorized to be appropriated sums for carbon capture utilization and storage demonstration projects at coal and gas plants.\n\nSEC. 99. SEVERABILITY.\nIf any provision of this Act, or the application thereof to any person or circumstance, is held invalid, the remainder of the Act, and the application of such provisions to other persons or circumstances, shall not be affected thereby.\n\nSEC. 100. EFFECTIVE DATE.\nThis Act shall take effect on the date of the enactment of this Act."},{"stance_key":"paris_accord","label":"Paris Accord Alignment","summary":"Binding NDC-style targets and methane rules.","policy_value":1,"full_text":"A BILL To align United States law with the Paris Agreement and strengthen methane regulation.\n\nBe it enacted by the Senate and House of Representatives of the United States of America in Congress assembled,\n\nSECTION 1. NDC IMPLEMENTATION.—The President shall submit to Congress an annual plan to meet nationally determined contribution targets, including sector-specific benchmarks for electricity, transportation, and buildings.\n\nSECTION 2. METHANE.—The Environmental Protection Agency shall issue performance standards for methane leaks from new and existing oil and gas production facilities.\n\nSECTION 3. GREEN BANK.—There is established a National Climate Bank to finance clean energy infrastructure in disadvantaged communities.\n\nSEC. 99. SEVERABILITY.\nIf any provision of this Act, or the application thereof to any person or circumstance, is held invalid, the remainder of the Act, and the application of such provisions to other persons or circumstances, shall not be affected thereby.\n\nSEC. 100. EFFECTIVE DATE.\nThis Act shall take effect on the date of the enactment of this Act."},{"stance_key":"green_new_deal","label":"Green New Deal Framework","summary":"Large-scale public jobs and decarbonization investment program.","policy_value":2,"full_text":"A BILL To mobilize public resources for a ten-year national mobilization against climate change.\n\nBe it enacted by the Senate and House of Representatives of the United States of America in Congress assembled,\n\nSECTION 1. MOBILIZATION GOALS.—Federal agencies shall prioritize projects that achieve one hundred percent clean, renewable, zero-emission energy sources for electricity not later than fifteen years after enactment.\n\nSECTION 2. JUST TRANSITION.—The Secretary of Labor shall administer grants for wage insurance, apprenticeship programs, and early retirement benefits for workers in carbon-intensive industries.\n\nSECTION 3. PUBLIC OWNERSHIP OPTION.—Municipalities may petition the Secretary of Energy for low-interest loans to acquire investor-owned utilities where consistent with state law.\n\nSEC. 99. SEVERABILITY.\nIf any provision of this Act, or the application thereof to any person or circumstance, is held invalid, the remainder of the Act, and the application of such provisions to other persons or circumstances, shall not be affected thereby.\n\nSEC. 100. EFFECTIVE DATE.\nThis Act shall take effect on the date of the enactment of this Act."}]'::jsonb) ON CONFLICT (issue_key) DO UPDATE SET display_name = excluded.display_name, description = excluded.description, stances = excluded.stances;
INSERT INTO public.bill_templates (issue_key, display_name, description, stances) VALUES ('student_debt', 'Student Debt', 'Repayment, forgiveness, and bankruptcy treatment.', '[{"stance_key":"no_action","label":"No Federal Forgiveness","summary":"Affirm current repayment structures; narrow PSLF fraud review only.","policy_value":-2,"full_text":"A BILL To reaffirm borrower responsibility for federal student loans.\n\nBe it enacted by the Senate and House of Representatives of the United States of America in Congress assembled,\n\nSECTION 1. NO BLANKET FORGIVENESS.—The Secretary of Education shall not implement any program of blanket loan cancellation except as expressly authorized in this title or subsequent Acts.\n\nSECTION 2. PSLF INTEGRITY.—The Secretary shall conduct audits of employer certifications for Public Service Loan Forgiveness and shall recover improperly forgiven amounts.\n\nSECTION 3. CAP INTEREST CAPITALIZATION.—Interest shall not capitalize more than once annually during periods of forbearance.\n\nSEC. 99. SEVERABILITY.\nIf any provision of this Act, or the application thereof to any person or circumstance, is held invalid, the remainder of the Act, and the application of such provisions to other persons or circumstances, shall not be affected thereby.\n\nSEC. 100. EFFECTIVE DATE.\nThis Act shall take effect on the date of the enactment of this Act."},{"stance_key":"income_based_reform","label":"Income-Based Reform","summary":"Cap payments at 5% discretionary income and shorten forgiveness horizon.","policy_value":-1,"full_text":"A BILL To reform income-driven repayment for federal student loans.\n\nBe it enacted by the Senate and House of Representatives of the United States of America in Congress assembled,\n\nSECTION 1. PAYMENT CAP.—Borrowers in an income-driven repayment plan shall pay five percent of discretionary income on undergraduate loans and ten percent on graduate loans.\n\nSECTION 2. FORGIVENESS HORIZON.—Remaining balances shall be forgiven after twenty years of qualifying payments for undergraduate borrowers and twenty-five years for graduate borrowers.\n\nSECTION 3. TAX TREATMENT.—Amounts forgiven shall not be treated as gross income for federal income tax purposes.\n\nSEC. 99. SEVERABILITY.\nIf any provision of this Act, or the application thereof to any person or circumstance, is held invalid, the remainder of the Act, and the application of such provisions to other persons or circumstances, shall not be affected thereby.\n\nSEC. 100. EFFECTIVE DATE.\nThis Act shall take effect on the date of the enactment of this Act."},{"stance_key":"partial_forgiveness","label":"Partial Forgiveness","summary":"Forgive $25,000 for Pell recipients meeting income tests.","policy_value":1,"full_text":"A BILL To provide targeted federal student loan forgiveness.\n\nBe it enacted by the Senate and House of Representatives of the United States of America in Congress assembled,\n\nSECTION 1. AMOUNT.—The Secretary of Education shall cancel up to $25,000 of outstanding principal and interest on eligible Federal Direct Loans for borrowers who received a Federal Pell Grant while enrolled.\n\nSECTION 2. INCOME PHASEOUT.—Benefits phase out beginning at modified adjusted gross income of $125,000 for single filers and $250,000 for joint filers.\n\nSECTION 3. SERVICER AUDIT.—The Secretary shall rebid loan servicing contracts with performance metrics tied to borrower outcomes.\n\nSEC. 99. SEVERABILITY.\nIf any provision of this Act, or the application thereof to any person or circumstance, is held invalid, the remainder of the Act, and the application of such provisions to other persons or circumstances, shall not be affected thereby.\n\nSEC. 100. EFFECTIVE DATE.\nThis Act shall take effect on the date of the enactment of this Act."},{"stance_key":"full_cancellation","label":"Full Cancellation","summary":"Cancel all federal student loan debt with revenue offset package.","policy_value":2,"full_text":"A BILL To cancel Federal Direct Loan obligations and establish offsets.\n\nBe it enacted by the Senate and House of Representatives of the United States of America in Congress assembled,\n\nSECTION 1. CANCELLATION.—The Secretary of Education shall discharge all principal and interest due on Federal Direct Loans and Federal Family Education Loans held by the Department as of the effective date.\n\nSECTION 2. CREDIT REPORTING.—Consumer reporting agencies shall delete tradelines relating to discharged loans within sixty days of notice from the Secretary.\n\nSECTION 3. OFFSETS.—The Joint Committee on Taxation shall report revenue measures sufficient to cover the budgetary effects of cancellation, including a surtax on ultra-high adjusted gross incomes as described in committee print.\n\nSEC. 99. SEVERABILITY.\nIf any provision of this Act, or the application thereof to any person or circumstance, is held invalid, the remainder of the Act, and the application of such provisions to other persons or circumstances, shall not be affected thereby.\n\nSEC. 100. EFFECTIVE DATE.\nThis Act shall take effect on the date of the enactment of this Act."}]'::jsonb) ON CONFLICT (issue_key) DO UPDATE SET display_name = excluded.display_name, description = excluded.description, stances = excluded.stances;
INSERT INTO public.bill_templates (issue_key, display_name, description, stances) VALUES ('drug_policy', 'Drug Policy', 'Scheduling, enforcement, decriminalization, and legalization frameworks.', '[{"stance_key":"stricter_enforcement","label":"Stricter Enforcement","summary":"Mandatory minimums for fentanyl analogues and federal-local task forces.","policy_value":-2,"full_text":"A BILL To increase penalties for trafficking in fentanyl-related substances.\n\nBe it enacted by the Senate and House of Representatives of the United States of America in Congress assembled,\n\nSECTION 1. SENTENCING.—Trafficking offenses involving detectable quantities of fentanyl or fentanyl analogues shall carry a ten-year mandatory minimum sentence absent substantial assistance.\n\nSECTION 2. TASK FORCES.—The Attorney General shall establish joint task forces in high-overdose counties combining DEA, FBI, and state and local officers.\n\nSECTION 3. PRECURSOR CONTROLS.—The Attorney General may by interim order schedule precursor chemicals pending permanent rulemaking.\n\nSEC. 99. SEVERABILITY.\nIf any provision of this Act, or the application thereof to any person or circumstance, is held invalid, the remainder of the Act, and the application of such provisions to other persons or circumstances, shall not be affected thereby.\n\nSEC. 100. EFFECTIVE DATE.\nThis Act shall take effect on the date of the enactment of this Act."},{"stance_key":"maintain_status_quo","label":"Maintain Status Quo","summary":"Codify current CSA schedules with research exceptions only.","policy_value":-1,"full_text":"A BILL To codify current drug scheduling and expand research access.\n\nBe it enacted by the Senate and House of Representatives of the United States of America in Congress assembled,\n\nSECTION 1. SCHEDULES.—The schedules of controlled substances in section 202 of the Controlled Substances Act shall remain as in effect on the day before the date of enactment, except as provided in subsection (b).\n\nSECTION 2. RESEARCH.—Registered investigators may obtain Schedule I substances for FDA-approved clinical trials through a centralized procurement office at the National Institutes of Health.\n\nSECTION 3. GRANTS.—There are authorized to be appropriated sums for state prescription drug monitoring program interoperability improvements.\n\nSEC. 99. SEVERABILITY.\nIf any provision of this Act, or the application thereof to any person or circumstance, is held invalid, the remainder of the Act, and the application of such provisions to other persons or circumstances, shall not be affected thereby.\n\nSEC. 100. EFFECTIVE DATE.\nThis Act shall take effect on the date of the enactment of this Act."},{"stance_key":"decriminalize","label":"Federal Decriminalization","summary":"Remove federal criminal penalties for personal possession; expunge records.","policy_value":1,"full_text":"A BILL To decriminalize personal possession of certain controlled substances under Federal law.\n\nBe it enacted by the Senate and House of Representatives of the United States of America in Congress assembled,\n\nSECTION 1. POSSESSION.—It shall not be a Federal crime for an adult to possess for personal use not more than thirty grams of marijuana or marijuana concentrate in jurisdictions that regulate marijuana.\n\nSECTION 2. EXPUNGEMENT.—The Attorney General shall establish an administrative process to vacate and expunge prior Federal convictions solely for covered possession offenses.\n\nSECTION 3. GRANTS.—The Bureau of Justice Assistance shall award grants for diversion and treatment programs.\n\nSEC. 99. SEVERABILITY.\nIf any provision of this Act, or the application thereof to any person or circumstance, is held invalid, the remainder of the Act, and the application of such provisions to other persons or circumstances, shall not be affected thereby.\n\nSEC. 100. EFFECTIVE DATE.\nThis Act shall take effect on the date of the enactment of this Act."},{"stance_key":"full_legalization","label":"Federal Legalization & Regulation","summary":"Deschedule cannabis, FDA-light labeling, state opt-out.","policy_value":2,"full_text":"A BILL To remove marijuana from the Controlled Substances Act and regulate interstate commerce.\n\nBe it enacted by the Senate and House of Representatives of the United States of America in Congress assembled,\n\nSECTION 1. REMOVAL.—Marijuana and tetrahydrocannabinols derived from marijuana shall be removed from all schedules under section 202 of the Controlled Substances Act.\n\nSECTION 2. FDA LABELING.—The Food and Drug Administration shall promulgate labeling and packaging rules for marijuana products sold in interstate commerce, including child-resistant packaging and potency caps for edible products.\n\nSECTION 3. STATE OPT-OUT.—A State may prohibit retail marijuana sales within its borders by enactment of a statute expressly referencing this section.\n\nSEC. 99. SEVERABILITY.\nIf any provision of this Act, or the application thereof to any person or circumstance, is held invalid, the remainder of the Act, and the application of such provisions to other persons or circumstances, shall not be affected thereby.\n\nSEC. 100. EFFECTIVE DATE.\nThis Act shall take effect on the date of the enactment of this Act."}]'::jsonb) ON CONFLICT (issue_key) DO UPDATE SET display_name = excluded.display_name, description = excluded.description, stances = excluded.stances;
